/// Plan C Task 81 — negative regression for the 9×9 Sudoku
/// solver's discharge-propagation path (PR #97 review iter 2 #8).
/// Unsolvable puzzle: two `5`s in row 0 (cells `[0,0] = 5` AND
/// `[0,1] = 5`) — `cell_valid` rejects every digit at the first
/// empty cell, every Choose.choose level exhausts via Choose.fail,
/// and `first_choice` returns `None` at the top.
///
/// The success-path test above (`task_81_sudoku_solves_9x9`)
/// exercises Choose.fail propagation DURING the search (intermediate
/// k(i) iterations of nested first_choice handles return None),
/// but the OUTERMOST first_choice's None branch is only hit when
/// every digit at every empty cell fails — i.e., on an unsolvable
/// puzzle. This test ensures the top-level discharge handle's
/// `None => "no solution"; 1` arm fires correctly: discharge
/// propagation through ~50 nested `solve_with_undo` handles
/// (each catching inner `Choose.fail` to run `mut_array_set(g, idx,
/// 0)` undo before re-raising) terminates cleanly at the
/// outermost `first_choice` with the None outcome, and main exits
/// with code 1 + stdout `"no solution\n"`.
#[test]
fn task_81_sudoku_unsolvable_puzzle_returns_no_solution() {
    let root = workspace_root();
    // Read the canonical Sudoku source, then patch a single line
    // to introduce a contradictory clue. We replace `array_set(g, 1, 3)`
    // (the `5,3,7` row 0 clue at col 1) with `mut_array_set(g, 1, 5)`
    // — wait, the file uses immutable Array, so the corresponding
    // line is `let g1: Array[Int] = array_set(g, 1, 3);`. Replace
    // the digit `3` with `5` to give row 0 two `5`s (cells 0 and 1).
    let original_path = root.join("examples/sudoku.sigil");
    let original = std::fs::read_to_string(&original_path).expect("read sudoku.sigil");

    // Sentinel-line replacement: convert `mut_array_set(g, 1, 3)`
    // (row 0 col 1 clue) to `mut_array_set(g, 1, 5)` (collision
    // with col 0's `5`). Use a fully-qualified pattern so a future
    // edit to the example doesn't accidentally match the wrong
    // line.
    let pattern = "let _s1: Unit = mut_array_set(g, 1, 3);";
    let replacement = "let _s1: Unit = mut_array_set(g, 1, 5);";
    assert!(
        original.contains(pattern),
        "expected sudoku.sigil to contain `{pattern}` for unsolvable-puzzle \
         test patch — if the example's clue scaffolding shape changed, \
         update this test's pattern accordingly"
    );
    let patched = original.replace(pattern, replacement);

    let src_path = std::env::temp_dir().join(format!(
        "sigil_e2e_sudoku_unsolvable_{}.sigil",
        std::process::id()
    ));
    std::fs::write(&src_path, patched).expect("write patched sudoku");

    let (stdout, stderr, code) = compile_file_and_run(&src_path, "sudoku_unsolvable");
    let _ = std::fs::remove_file(&src_path);

    assert_eq!(
        code, 1,
        "unsolvable-puzzle sudoku must exit 1 via `None => 1` arm; \
         stdout={stdout:?} stderr={stderr:?}"
    );
    assert_eq!(
        stdout, "no solution\n",
        "unsolvable-puzzle sudoku must print `no solution` via the \
         outermost first_choice's None branch; stderr={stderr:?}"
    );
}

// ===== Plan A3 Task 45 — E0120 non-exhaustive-match regression ==============

/// Compile a deliberately non-exhaustive `match` on `Option` with
/// `--human-errors` and assert the compile failure surfaces E0120 plus
/// the counterexample witness `None` in stderr. This pins both the
/// code-emission path (which Plan B refines) and the witness-string
/// generator (Task 38.4) against silent regression.
#[test]
fn e0120_non_exhaustive_match_names_witness_in_stderr() {
    let source = "type Option = | None | Some(Int)\n\
                  fn f(o: Option) -> Int ![] {\n  \
                    match o {\n    \
                      Some(n) => n,\n  \
                    }\n\
                  }\n\
                  fn main() -> Int ![] { 0 }\n";

    let src_path = std::env::temp_dir().join(format!(
        "sigil_e2e_e0120_non_exhaustive_{}.sigil",
        std::process::id()
    ));
    std::fs::write(&src_path, source).expect("write source");
    let bin_path = std::env::temp_dir().join(format!(
        "sigil_e2e_e0120_non_exhaustive_{}",
        std::process::id()
    ));

    let root = workspace_root();
    let sigil_bin = sigil_binary();
    let compile = Command::new(&sigil_bin)
        .arg(&src_path)
        .arg("-o")
        .arg(&bin_path)
        .arg("--human-errors")
        .current_dir(&root)
        .output()
        .expect("failed to invoke sigil compiler");

    let _ = std::fs::remove_file(&src_path);
    let _ = std::fs::remove_file(&bin_path);

    assert!(
        !compile.status.success(),
        "compile must fail for a non-exhaustive Option match; stdout={} stderr={}",
        String::from_utf8_lossy(&compile.stdout),
        String::from_utf8_lossy(&compile.stderr),
    );
    let stderr = String::from_utf8_lossy(&compile.stderr);
    assert!(
        stderr.contains("E0120"),
        "stderr missing E0120 code: {stderr}"
    );
    // The witness string names the uncovered variant. `None` is a Unit
    // variant so the witness is the bare constructor name (no
    // parentheses / braces).
    assert!(
        stderr.contains("None"),
        "stderr missing witness `None`: {stderr}"
    );
}

// ===== Plan B Task 50 — `--dump-color` ====================================

/// `sigil <input> --dump-color` runs the front end through color
/// inference and prints one stable line per monomorph to stdout, then
/// exits 0 without producing an executable. The hello-world example
/// has a single `main` fn with row `![IO]`, which the color analysis
/// classifies as native: pure row, leaf call graph (modulo perform IO
/// which the local analysis treats as part of the IO-only row, not a
/// non-IO body site).
#[test]
fn dump_color_hello_is_cps_row_io() {
    let root = workspace_root();
    let source = root.join("examples/hello.sigil");
    let sigil_bin = sigil_binary();
    let out = Command::new(&sigil_bin)
        .arg(&source)
        .arg("--dump-color")
        .output()
        .expect("invoke sigil --dump-color");
    let stdout = String::from_utf8_lossy(&out.stdout);
    let stderr = String::from_utf8_lossy(&out.stderr);
    assert!(
        out.status.success(),
        "--dump-color exit; stdout={stdout:?}, stderr={stderr:?}"
    );
    // hello.sigil declares `fn main() -> Int ![IO]`. Stage 6 cleanup
    // lifted the IO color filter — `![IO]`-rowed fns now classify
    // as CPS-color (matching every other effect). main is special-
    // cased to `UserFnAbi::Sync` regardless of color (per
    // `compute_user_fn_abi`'s main entry-point contract), so the
    // ABI is still Sync and the runtime behavior matches the shim's
    // expectations; only the colorer's reason text changed.
    assert!(
        stdout.contains("main cps"),
        "expected `main cps ...` in dump-color output, got: {stdout}"
    );
    // Pin the reason text to the post-lift form so a regression
    // re-introducing the IO color exemption surfaces here.
    assert!(
        stdout.contains("cps: row contains effect `IO`"),
        "expected reason `cps: row contains effect `IO``, got: {stdout}"
    );
}

/// A multi-fn program: `helper` is pure, `main` calls `helper`. Both
/// classify as native; `main`'s reason is the local "native" reason
/// (not the transitive-CPS branch). The dump comes back in program
/// order.
#[test]
fn dump_color_multi_fn_pure_program() {
    let src = r#"
        fn helper(n: Int) -> Int ![] { n + 1 }
        fn main() -> Int ![] { helper(41) }
    "#;
    let tmp = std::env::temp_dir().join(format!(
        "sigil_e2e_dump_color_pure_{}.sigil",
        std::process::id()
    ));
    std::fs::write(&tmp, src).expect("write tmp source");
    let sigil_bin = sigil_binary();
    let out = Command::new(&sigil_bin)
        .arg(&tmp)
        .arg("--dump-color")
        .output()
        .expect("invoke sigil --dump-color");
    let _ = std::fs::remove_file(&tmp);
    let stdout = String::from_utf8_lossy(&out.stdout);
    let stderr = String::from_utf8_lossy(&out.stderr);
    assert!(
        out.status.success(),
        "exit; stdout={stdout:?}, stderr={stderr:?}"
    );
    // Program order: helper then main.
    assert_eq!(
        stdout.trim_end(),
        "helper native native: pure row\nmain native native: pure row",
        "dump-color output mismatch: {stdout}",
    );
}

