/// **Pin wrapper-fn-frame composition** for the `std/state` surface
/// (closure of `[DEVIATION Task 72]` constraint #3 via Plan D Task
/// 112). User-side wrapper fns (`get_state` / `set_state`) introduce
/// a function-call frame between the body's call site and the
/// underlying `perform State.x`. Pre-Task-112 the discharge-with-
/// lambda continuation chain produced the initial value `5` instead
/// of the threaded `11` (the failure shape that surfaced on PR #45's
/// first CI run with commit `c71c1e4`). Post-Task-112 the chained-
/// let-yield classifier accepts wrapper-Call let-RHS and the helper-
/// body / Middle-step emit threads the chain's k-pair through the
/// wrapper boundary.
///
/// Test name retains the historical "_pending_v2_wrapper_fn_frame_fix"
/// suffix as a permanent pointer to the closure event in commit
/// history; future cleanup may rename to drop the "pending" framing.
#[test]
fn std_state_run_state_via_wrappers_pending_v2_wrapper_fn_frame_fix() {
    let src = "import std.int\n\
               import std.io\n\
               import std.state\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               use std.state.{State, run_state};\n\
               fn get_state() -> Int ![State[Int]] { perform State.get() }\n\
               fn set_state(s: Int) -> Int ![State[Int]] { perform State.set(s) }\n\
               fn comp() -> Int ![State[Int]] {\n\
               let _: Int = set_state(10);\n\
               let v: Int = get_state();\n\
               v + 1\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let pair: (Int, Int) = run_state(5, comp);\n\
               let v: Int = match pair { (v, _) => v };\n\
               perform IO.println(int_to_string(v));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "std_state_via_wrappers_pending");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // Future-correct (v2): wrappers thread state via discharge-with-
    // lambda chain identically to the inline-perform shape; result is
    // the canonical `11`.
    assert_eq!(
        stdout, "11\n",
        "expected wrapper-fn-frame composition to thread state \
         identically to inline-perform; pre-v2 actual is \"5\\n\" \
         (initial value passes through). stderr={stderr:?}"
    );
}

/// Plan D Task 112 — wrapper-fn-frame composition fix. Self-contained
/// version of `std_state_run_state_via_wrappers_pending_v2_wrapper_fn_frame_fix`
/// that pins the codegen-side gap (no stdlib dependency). Pre-fix:
/// `set_state(10)` wraps `perform S.set(10)`; the calling fn's body
/// `let _ = set_state(10); let v = get_state(); v + 1` selects Sync
/// ABI because the chained-let-yield classifier rejects wrapper-Call
/// in let-RHS. The Sync→Cps interop wrapper hardcodes
/// `(null_k_closure, identity_k_fn)` as the trailing pair; the
/// discharge-with-lambda arm `fn (s) => k(arg)(arg)` thus captures
/// identity and produces garbage instead of the threaded state.
/// Post-fix: classifier accepts wrapper-Call let-RHS; calling fn
/// becomes Cps; wrapped-Cps-call k-pair threading delivers the real
/// continuation; result = 11 (set 10, get 10, tail = 10+1).
#[test]
fn task_112_wrapper_fn_frame_composition_state_set_get_returns_11() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               effect S resumes: many {\n\
                 get: () -> Int,\n\
                 set: (Int) -> Int,\n\
               }\n\
               fn set_state(n: Int) -> Int ![S] { perform S.set(n) }\n\
               fn get_state() -> Int ![S] { perform S.get() }\n\
               fn comp() -> Int ![S] {\n\
                 let _: Int = set_state(10);\n\
                 let v: Int = get_state();\n\
                 v + 1\n\
               }\n\
               fn run_state(initial: Int, body: () -> Int ![S]) -> Int ![] {\n\
                 let state_fn: (Int) -> Int ![] = handle body() with {\n\
                   return(v) => fn (s: Int) -> Int ![] => v,\n\
                   S.get(k) => fn (s: Int) -> Int ![] => k(s)(s),\n\
                   S.set(arg, k) => fn (s: Int) -> Int ![] => k(arg)(arg),\n\
                 };\n\
                 state_fn(initial)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let result: Int = run_state(0, comp);\n\
                 perform IO.println(int_to_string(result));\n\
                 0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "task_112_wrappers_set_get");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "11\n",
        "Task 112 post-fix: wrappers compose with discharge-with-lambda — \
         set_state(10) → S.set(10) threads 10; get_state() → S.get() returns \
         10; tail v+1 = 11. Pre-fix actual is garbage (often `0\\n` or \
         `5\\n` depending on initial-value pass-through). stderr={stderr:?}"
    );
}

/// Plan D Task 112b — chained-let-yield Cps wrapper composition fix.
/// Self-contained test exercising a chained-let-yield Cps wrapper
/// (`double_set` body has chain_length=2 with a pure tail) called as
/// `let _ = double_set(10, 20)` inside `comp`'s chained-let-yield
/// body, against a discharge-with-lambda handler (run_state).
///
/// **Pre-fix (Task 112a state):** `is_tail_perform_cps_user_fn` lookup
/// rejects `double_set` (it's chained-let-yield, not tail-perform).
/// Classifier rejects this `Expr::Call` let-RHS; `comp` falls back to
/// Sync ABI; lower_call's Cps branch handles `double_set` via the
/// SAVE+CLEAR+RESTORE BODY_RETURN_ARM mechanism. Under discharge-
/// with-lambda the lambda chain breaks (chained-let-yield wrapper's
/// inner perform captures the wrapper's INTERNAL chain pair, NOT
/// the caller's k, so state-threading via `state_fn(initial)` walks
/// the wrong chain).
///
/// **Post-fix (Task 112b):** classifier widened to accept chained-
/// let-yield Cps callees; chain step closure records carry the
/// caller's trailing-pair (caller_k_pair) end-to-end; the wrapper's
/// own Final chain step substitutes its terminal
/// `done_or_dispatch_return_arm(tail)` with
/// `NextStep::Call(caller_k_pair, [tail, null, identity], 3)`, which
/// dispatches the caller's continuation directly with `tail`. At
/// top-level (caller_k_pair = (null, identity_k_fn)) this routes via
/// identity → `Done(tail)` so the surrounding handle's Phase 4g
/// wraps via return arm normally. Inside an outer chained-let-yield
/// caller, the caller_k_pair points at the next chain step's synth-
/// cont, so the wrapper's tail flows directly into the caller's
/// chain — no need for OUTER_POST_ARM_K_STACK routing.
///
/// Expected: `"21\n"` (set 10, set 20 — state threads to 20; tail
/// `v+1` = 21).
#[test]
fn task_112b_chained_let_yield_wrapper_state_threading_returns_21() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               effect S resumes: many {\n\
                 get: () -> Int,\n\
                 set: (Int) -> Int,\n\
               }\n\
               fn double_set(a: Int, b: Int) -> Int ![S] {\n\
                 let _a: Int = perform S.set(a);\n\
                 let _b: Int = perform S.set(b);\n\
                 0\n\
               }\n\
               fn comp() -> Int ![S] {\n\
                 let _c: Int = double_set(10, 20);\n\
                 let v: Int = perform S.get();\n\
                 v + 1\n\
               }\n\
               fn run_state(initial: Int, body: () -> Int ![S]) -> Int ![] {\n\
                 let state_fn: (Int) -> Int ![] = handle body() with {\n\
                   return(v) => fn (s: Int) -> Int ![] => v,\n\
                   S.get(k) => fn (s: Int) -> Int ![] => k(s)(s),\n\
                   S.set(arg, k) => fn (s: Int) -> Int ![] => k(arg)(arg),\n\
                 };\n\
                 state_fn(initial)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let result: Int = run_state(0, comp);\n\
                 perform IO.println(int_to_string(result));\n\
                 0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "task_112b_chained_wrapper_state");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "21\n",
        "Task 112b post-fix: chained-let-yield Cps wrapper composition \
         under discharge-with-lambda — double_set threads state through \
         its internal chain, then comp continues with comp_step_0 firing \
         after double_set's Done; perform S.get returns 20; tail v+1 = 21. \
         stderr={stderr:?}"
    );
}

