/// **G3 representative test — expression-position polymorphism in if-branch.**
///
/// Pinned shape (constructed, not Koka-imported): `if b { raise("nope")
/// } else { 42 }` where `raise[A, E](e: E) -> A ![Raise[E]]`. The
/// per-op fresh A from `raise` should infer to `Int` from the else
/// branch's `42` literal, but typecheck fires **E0063 "if branches
/// have incompatible types: then is `?N` but else is `Int`"** before
/// the cross-branch unification can pin A.
///
/// ## Status — gap representative for G3 (own gap, surfaced by Task 78.5)
///
/// **`#[ignore]`'d**: surfaced from the multi-effect interpreter port
/// (G2.b test above) when a `raise` call appears in expression position
/// inside an if-branch. The workaround `let _r: Int = raise(...); _r`
/// converts the expression to a let-binding and pins A via ascription.
/// The workaround is acceptable in practice but G3 is a real
/// **expression-position polymorphism inference gap** distinct from
/// G2.a / G2.b — it lives in the if-branch unification path, not the
/// row-poly call-site path.
///
/// ## G3 root site
///
/// `compiler/src/typecheck.rs` if-branch unification — likely
/// `check_if` or the `match`-arm cross-branch unify entry. Fires
/// E0063 before the per-op A from `raise[A, E]` is bound. The
/// expected behavior: cross-branch unify at the if's join point
/// should drive A := Int from the else branch's literal type. The
/// observed behavior: typecheck checks the then-branch in isolation,
/// observes the unbound A, and emits E0063 against the else's Int.
///
/// ## Closure path
///
/// TBD by fix author. Likely site: the if-expression typecheck arm in
/// `check_expr` — needs to defer the cross-branch unify until both
/// branches have been checked, then unify the per-op fresh vars
/// against each other before emitting E0063.
///
/// **NOT** in the same family as G2.a / G2.b (those are row-poly
/// inference; G3 is type-poly inference at expression position). Per
/// reviewer ask: "don't bury this in a doc-comment as 'not a gap'" —
/// pinned as its own ignored test.
///
/// **Invariant** (post-fix): `safe_or_default(true)` returns nothing
/// (raises); `safe_or_default(false)` returns 42. With the surrounding
/// catch wrapping, returns `Err("nope")` for true, `Ok(42)` for false.
/// stdout for `safe_or_default(false)` = `"42\n"`, exit 0.
#[test]
fn task_78_5_pending_g3_raise_in_if_branch_expr_position_polymorphism() {
    let src = "import std.int\n\
               import std.raise\n\
               import std.result\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               use std.raise.{Raise, catch, raise};\n\
               use std.result.{Err, Ok, Result};\n\
               \n\
               fn safe_or_default(b: Bool) -> Int ![Raise[String]] {\n\
               if b {\n\
               raise(\"nope\")\n\
               } else {\n\
               42\n\
               }\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let r: Result[Int, String] = catch(fn () -> Int ![Raise[String]] => safe_or_default(false));\n\
               match r {\n\
               Ok(v) => perform IO.println(int_to_string(v)),\n\
               Err(m) => perform IO.println(m),\n\
               };\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "task_78_5_pending_g3_raise_in_if_branch");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "42\n",
        "post-fix safe_or_default(false) should yield Ok(42); stderr={stderr:?}"
    );
}

/// **Task 78.5 G2.a — minimal regression pin: bracketed `[e]` aliases
/// row var, no lambda involvement.**
///
/// Constructed (not Koka-imported). Isolates G2.a alone — single
/// row-poly fn `ask_then_double[e]` with bracketed `[e]` aliasing the
/// `| e` row variable, plus a single-arm handle that doesn't introduce
/// any lambda with a row-bearing surface row. Sister test
/// `task_78_5_pending_g2a_bracketed_e_alias_unconstrained` (still
/// `#[ignore]`'d below, blocked on G2.b) is the third-party-grounded
/// Plotkin port that exercises G2.a + G2.b together.
///
/// ## Pre-fix failure
///
/// E0132 "ambiguous polymorphism: type parameter `e` of
/// `ask_then_double` is unconstrained at this call site" at
/// `ask_then_double(doer)`. Pre-fix, the parser produces both
/// `f.generic_params = [GenericParam{e}]` (TYPE kind, from the
/// bracketed `[e]`) and `f.effect_row_var = Some(RowVar{e})` (ROW
/// kind, from `| e`). The type-kind alias is allocated at scheme
/// registration but never pinned by any body reference (the body uses
/// `e` only in row positions), so the post-typecheck E0132 sweep at
/// typecheck.rs:1346-1370 reports it unconstrained at every call.
///
/// ## Post-fix invariant
///
/// `effective_fn_generic_params` strips the alias at scheme
/// registration / `check_fn` entry; the type-var slot is never
/// allocated and the sweep sees no unbound var. The handler resumes
/// `Eff.ask` with `21`; `doer` returns `21 + 21 = 42`. stdout =
/// `"42\n"`, exit 0.
#[test]
fn task_78_5_g2a_minimal_bracketed_e_alias_typechecks() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect Eff { ask: () -> Int }\n\
               \n\
               fn ask_then_double[e](action: () -> Int ![Eff | e]) -> Int ![| e] {\n\
               handle action() with {\n\
               Eff.ask(k) => k(21),\n\
               }\n\
               }\n\
               \n\
               fn doer() -> Int ![Eff] {\n\
               let v: Int = perform Eff.ask();\n\
               v + v\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let n: Int = ask_then_double(doer);\n\
               perform IO.println(int_to_string(n));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "task_78_5_g2a_minimal_bracketed_e_alias");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "42\n",
        "ask_then_double resumes Eff.ask with 21; doer returns 21+21=42; \
         stderr={stderr:?}"
    );
}

/// **Task 78.5 — State+Choose Plotkin combo, state(amb) order [STILL PENDING — G2.b blocking].**
///
/// Source pattern: `koka/test/algeff/effs1a.kk` test2 — the canonical
/// "stateful nondeterminism" demo from algebraic-effects literature.
///
/// ## Status — gap representative for G2.a + G2.b combined
///
/// **`#[ignore]`'d post-G2.a-fix**: G2.a is closed (the bracketed
/// `[e]` alias on `amb_handle` no longer fires E0132), but this test
/// still fails because `run_state_poly`'s body uses lambdas with
/// `![| e]` surface rows (`fn (s: Int) -> A ![| e] => ...`) that
/// drop the row variable, surfacing G2.b (E0128 "effect row mismatch:
/// closed row `![]` cannot unify with open row `![| e]`"). The
/// minimal G2.a-only regression is
/// `task_78_5_g2a_minimal_bracketed_e_alias_typechecks` above; this
/// larger test will un-ignore once G2.b lands.
///
/// ## G2.a root site (now closed)
///
/// `compiler/src/typecheck.rs:1346-1370` (the post-typecheck E0132
/// sweep over `pending_call_instantiations`). Upstream root: the AST
/// parser (parser.rs:391-405 + 418-422) splits "bracketed generic
/// params" (`f.generic_params`, parsed as TYPE GenericParam) from
/// "row variable" (`f.effect_row_var`, set only by `| e` syntax).
/// When the user writes `fn amb_handle[e](action: () -> Bool ![Amb |
/// e]) -> List[Bool] ![| e]` intending `e` as a row variable, the
/// parser produced BOTH `f.generic_params = [GP{e}]` (type kind) AND
/// `f.effect_row_var = Some(RowVar{e})` (row kind) — **two different
/// variables sharing a name**. The type variable was allocated at
/// scheme-registration (typecheck.rs:1114, `fresh_generic_subst`) and
/// at check_fn entry (:3785), but no surface reference ever pinned it
/// (nothing in the body uses `e` in TypeExpr position), so the
/// post-typecheck sweep at 1346-1370 found it unbound and fired
/// E0132. **G2.a fix landed: `effective_fn_generic_params` strips the
/// alias at the four FnDecl-consuming sites; the type-var slot is no
/// longer allocated.**
///
/// ## Why this test is still ignored — G2.b blocking
///
/// `run_state_poly`'s body uses lambdas with `![| e]` row surfaces
/// (`fn (s: Int) -> A ![| e] => v`). G2.b (lambda drops the parsed
/// row variable at typecheck.rs:4328 / :4743) collapses the lambda's
/// row to closed; the surrounding `let state_fn: (Int) -> A ![| e]
/// = ...` symmetric unify_row binds `run_state_poly`'s outer row var
/// to closed empty, surfacing E0128 at the call-site row-mismatch.
/// Will un-ignore once G2.b lands.
///
/// ## Why it's novel for sigil
///
/// **Stateful nondeterminism is the single most-cited gap in standard
/// algebraic-effect literature.** The existing corpus has State alone,
/// Choose alone, but never composed. Order matters semantically:
/// state(amb) shares state across choices; amb(state) gives each branch
/// its own state copy.
///
/// **Invariant** (post-G2.b-fix): `body` performs flip then increments
/// state. `amb_handle` resumes both branches; the outer
/// `run_state_poly` shares the State frame across both. Final list =
/// `[true, false]`; length = 2; stdout = `"2\n"`.
#[test]
fn task_78_5_pending_g2a_bracketed_e_alias_unconstrained() {
    // Inline row-poly + body-type-poly run_state (mirrors std/raise.sigil's
    // catch shape). std/state.sigil's run_state is closed-row + Int-only,
    // which can't accept a body returning List[Bool] with extra effects.
    let src = "import std.int\n\
               import std.list\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               use std.list.{Cons, List, Nil, append, length};\n\
               \n\
               effect State resumes: many { get: () -> Int, set: (Int) -> Int }\n\
               effect Amb resumes: many { flip: () -> Bool }\n\
               \n\
               fn run_state_poly[A](initial: Int, body: () -> A ![State | e]) -> A ![| e] {\n\
               let state_fn: (Int) -> A ![| e] = handle body() with {\n\
               return(v) => fn (s: Int) -> A ![| e] => v,\n\
               State.get(k) => fn (s: Int) -> A ![| e] => k(s)(s),\n\
               State.set(arg, k) => fn (s: Int) -> A ![| e] => k(arg)(arg),\n\
               };\n\
               state_fn(initial)\n\
               }\n\
               \n\
               fn body() -> Bool ![Amb, State] {\n\
               let p: Bool = perform Amb.flip();\n\
               let i: Int = perform State.get();\n\
               let _: Int = perform State.set(i + 1);\n\
               p\n\
               }\n\
               \n\
               fn amb_handle[e](action: () -> Bool ![Amb | e]) -> List[Bool] ![| e] {\n\
               handle action() with {\n\
               Amb.flip(k) => {\n\
               let r1: List[Bool] = k(true);\n\
               let r2: List[Bool] = k(false);\n\
               append(r1, r2)\n\
               },\n\
               return(v) => Cons(v, Nil),\n\
               }\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let result: List[Bool] = run_state_poly(0, fn () -> List[Bool] ![State] => amb_handle(body));\n\
               perform IO.println(int_to_string(length(result)));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "task_78_5_plotkin_state_amb");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "2\n",
        "Plotkin state(amb): list of both flip outcomes has length 2; \
         stderr={stderr:?}"
    );
}

/// **Task 78.5 G4 Phase B.3 — CPS→CPS direct dispatch from synth-cont
/// tail (non-recursive helper).**
///
/// Pins B.3's direct `NextStep::Call` dispatch from the
/// `CompoundMatchArmPostPerform` synth-cont's tail: when the synth-cont's
/// `tail_expr` is a direct call to a Cps-ABI top-level user fn, codegen
/// emits a `NextStep::Call(target_cps, [args, post_arm_k_pair], N+2)`
/// returning to the OUTER trampoline, instead of routing through
/// `Lowerer::lower_expr` → `lower_call`'s Cps branch (which would pack
/// `(null, identity)` as the callee's trailing pair AND drive a NESTED
/// `sigil_run_loop`, violating the trampoline charter per
/// `feedback_sigil_trampoline_charter`).
///
/// **Shape (intentionally non-recursive):** `caller`'s body is `match
/// xs { Nil => 0, Cons(x, _) => { let _ = perform Gen.yield(x);
/// helper(x) } }`. The Cons arm's tail is `helper(x)` — a Cps user fn
/// call (helper's body is the chained-let-yield-then-pure-tail shape,
/// classified Cps). The non-recursive shape pins B.3's dispatch
/// mechanics independent of the recursive Generator shape (which the
/// closeout PR exercises via
/// `task_78_5_pending_g4_recursive_perform_in_match_arm_body`).
///
/// **Trace (unwinding the trampoline hops):**
///   1. main: `handle caller(Cons(7, Nil)) with { Gen.yield(_, k) => k(0) }`.
///      No return arm, so handle takes the standard path: `lower_call`'s
///      Cps branch packs `(null, identity)` and drives `sigil_run_loop`
///      synchronously to unwind to a Sync return.
///   2. caller's body emit: B.1's compound-match dispatch fires; `Cons`
///      arm allocates B.2's synth-cont (capturing `x = 7`), issues
///      `sigil_perform(Gen.yield(7), k = (synth_cont_closure, synth_-
///      cont_fn))`.
///   3. Trampoline → handler arm `Gen.yield(_, k) => k(0)`. `k(0)` packs
///      `[0, NULL, identity]` and dispatches to synth_cont via
///      `next_step_call`.
///   4. synth-cont fires: loads `x = 7` from closure record, binds
///      `let _ = args_ptr[0] = 0` (discarded). **B.3 fires here**:
///      `tail_expr = helper(x)` matches Cps user fn detector. Emit
///      `next_step_call(NULL, helper_addr, 3)` with args buffer
///      `[7, NULL, identity]` (forwarded from synth-cont's incoming
///      post_arm_k pair). Return NS up to outer trampoline.
///   5. Trampoline → helper(NULL, [7, NULL, identity], 3). helper's
///      body: chained-let with 1 step + tail `n + 100`. The chain Final
///      step lowers `n + 100 = 7 + 100 = 107`, dispatches via incoming
///      post_arm_k pair `(NULL, identity)` → `next_step_call(NULL,
///      identity, [107], 1)`.
///   6. Trampoline → identity(NULL, [107], 1) → returns `Done(107)`.
///   7. run_loop returns 107 to main's handle expression.
///   8. main: `IO.println(int_to_string(107))` → stdout `"107\n"`.
///
/// **What B.3 specifically gives us:** the hop at step 5 is the OUTER
/// trampoline (the one that started at step 1) dispatching helper
/// directly. Pre-B.3 step 4 would call `lower_call`'s Cps branch on
/// `helper(x)`, spawning a NESTED `sigil_run_loop` to drive helper's
/// body (one extra trampoline level per recursive perform — exactly
/// the trampoline-charter violation B.3 closes).
///
/// **Invariant**: stdout = `"107\n"`, exit 0.
#[test]
fn task_78_5_g4_b3_non_recursive_cps_to_cps_direct_dispatch_in_synth_cont_tail() {
    // Inline `Gen` effect + `IntList` ADT — no `import std.list` so the
    // test stands alone. Both `helper` and `caller` are Cps user fns;
    // caller's Cons-arm tail is `helper(x)` → triggers B.3 detection.
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect Gen { yield: (Int) -> Int }\n\
               \n\
               type IntList = | Nil | Cons(Int, IntList)\n\
               \n\
               fn helper(n: Int) -> Int ![Gen] {\n\
               let _: Int = perform Gen.yield(n);\n\
               n + 100\n\
               }\n\
               \n\
               fn caller(xs: IntList) -> Int ![Gen] {\n\
               match xs {\n\
               Nil => 0,\n\
               Cons(x, _) => {\n\
               let _: Int = perform Gen.yield(x);\n\
               helper(x)\n\
               },\n\
               }\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let xs: IntList = Cons(7, Nil);\n\
               let result: Int = handle caller(xs) with {\n\
               Gen.yield(_x, k) => k(0),\n\
               };\n\
               perform IO.println(int_to_string(result));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(
        src,
        "task_78_5_g4_b3_non_recursive_cps_to_cps_direct_dispatch_in_synth_cont_tail",
    );
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "107\n",
        "B.3 direct dispatch: caller's synth-cont tail `helper(x)` \
         (with x=7 captured from arm pattern) emits `NextStep::Call \
         (helper, [7, NULL, identity], 3)` to the outer trampoline; \
         helper's body resumes the perform chain with k(0), discards \
         the 0, lowers `n + 100 = 107`, dispatches Done(107) via the \
         forwarded `(NULL, identity)` trailing pair. If output is \
         shape-different (e.g., 100 from helper running in a nested \
         run_loop with broken capture handling), B.3's direct-dispatch \
         args-packing or post-arm-k forwarding regressed. \
         stderr={stderr:?}"
    );
}

/// **Plan D Task 111d — caller-owned terminal channel propagation.**
///
/// Pins the new pointer-side path end-to-end: a handle-exit terminal
/// value (DISCHARGED tag + payload) must flow through nested Sync
/// user-fn calls (each thread its caller's `*mut TerminalResult` as
/// the trailing ABI param), be written by `sigil_run_loop` at the
/// innermost perform site (`*out = TerminalResult { value, tag }`),
/// and be observed by the outer handle's tag/value loads from the
/// SAME caller-owned slot.
///
/// Test shape — three levels of Sync user fn nesting between the
/// handle and the perform:
///
///   ```sigil
///   handle a() with { Eff.kill(_,_) => 17 }
///   ```
///   - `a()` calls `b()`, `b()` calls `c()`, `c()` performs `Eff.kill`.
///   - The arm discards `k` and returns `17`, which the trampoline
///     records as DISCHARGED with value 17.
///   - The terminal flow: c's perform site's `sigil_run_loop` writes
///     `*out = (17, DISCHARGED)`. c returns. b returns. a returns to
///     the handle expression. The handle-exit tag-load reads
///     `*out.tag = DISCHARGED` from the SAME slot (threaded down 3
///     levels and back), routes to the discharge_block, loads
///     `*out.value = 17`, narrows to `Int`, and returns 17 as the
///     handle's overall.
///
/// Pre-111d this routing went through TLS (`LAST_TERMINAL_TAG` /
/// `LAST_TERMINAL_VALUE`); 111d removed TLS and made the
/// caller-owned slot the sole terminal channel. If 111d's ABI
/// threading (Sync→Sync trailing-param forwarding) or the run_loop's
/// `*out` write or codegen's load is broken, the discharge tag won't
/// be observed at handle exit, return-arm dispatch fires
/// incorrectly, and the output diverges from `"17\n"`.
///
/// **Invariant:** stdout = `"17\n"`, exit 0.
#[test]
fn task_111d_terminal_channel_propagation_through_nested_sync_calls() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect Eff { kill: () -> Int }\n\
               \n\
               fn c() -> Int ![Eff] {\n\
               perform Eff.kill()\n\
               }\n\
               \n\
               fn b() -> Int ![Eff] {\n\
               c()\n\
               }\n\
               \n\
               fn a() -> Int ![Eff] {\n\
               b()\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let r: Int = handle a() with {\n\
               Eff.kill(_k) => 17,\n\
               };\n\
               perform IO.println(int_to_string(r));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(
        src,
        "task_111d_terminal_channel_propagation_through_nested_sync_calls",
    );
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "17\n",
        "Plan D Task 111d: handle-exit terminal value (17, DISCHARGED) \
         must propagate through 3 levels of Sync user fn calls (a → b → \
         c) via the caller-owned `*mut TerminalResult` slot threaded as \
         the trailing Sync ABI param. The arm discards k and returns \
         17; the trampoline writes (17, DISCHARGED) to the slot at the \
         perform site's run_loop terminal; codegen at the handle exit \
         loads tag and value from the SAME slot and routes through \
         discharge_block. stderr={stderr:?}"
    );
}

/// **Plan D Task 111d PR #92 R1 issue 1 — nested-handle slot leak.**
///
/// Pins the snapshot/restore discipline at every handle expression's
/// entry/exit boundary. The surrounding fn's `terminal_out_param`
/// slot is shared across every handle expression in the fn AND every
/// nested `sigil_run_loop` call. Without snapshot/restore, an inner
/// handle whose op-arm DISCHARGES leaves `(value, DISCHARGED)` in
/// the slot; the outer handle's exit-tag query then reads the
/// inner's leftover and incorrectly:
///
/// 1. Skips the outer's return arm (DISCHARGED → discharge_block),
///    AND
/// 2. Loads the inner's leftover value as the handle's overall.
///
/// The fix snapshots the slot at handle entry and restores it at
/// every exit path (return-arm and no-return-arm merge-blocks).
/// This test program's expected output:
///
///   - `outer_body` performs `E1.op1()` (resumed by main's E1 arm
///     via `k(0)` → run_loop terminates DONE, slot = (0, DONE))
///   - inner handle: `inner_body()` performs `E2.op2()` which the
///     inner arm DISCHARGES with 99 → slot = (99, DISCHARGED).
///     Inner's exit reads tag = DISCHARGED → discharge_block →
///     `inner = 99`.
///   - **Inner's exit restores the snapshot** = (0, DONE).
///   - `outer_body` continues: `inner * 10 = 990`. Returns 990.
///   - main's outer handle exit: reads tag = DONE (snapshot
///     correctly restored) → return arm fires: `990 + 100 = 1090`.
///
/// Pre-fix output is `99\n` (inner's discharged value leaked through
/// outer's exit). Post-fix output is `1090\n`.
///
/// Pre-111d this leak existed identically in TLS form (the inner's
/// run_loop also wrote `LAST_TERMINAL_TAG = DISCHARGED` which the
/// outer's exit-tag query read), but no test exercised the
/// composition. Brian flagged the gap on PR #92 R1 issue 1; the
/// snapshot/restore fix lands in 111d before declaring `[DEVIATION
/// Task 111]` fully closed.
///
/// **Invariant:** stdout = `"1090\n"`, exit 0.
#[test]
fn task_111d_nested_handle_inner_discharge_does_not_leak_to_outer() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect E1 { op1: () -> Int }\n\
               effect E2 { op2: () -> Int }\n\
               \n\
               fn inner_body() -> Int ![E2] {\n\
               let _: Int = perform E2.op2();\n\
               7\n\
               }\n\
               \n\
               fn outer_body() -> Int ![E1, E2] {\n\
               let _: Int = perform E1.op1();\n\
               let inner: Int = handle inner_body() with {\n\
               E2.op2(_k) => 99,\n\
               };\n\
               inner * 10\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let outer: Int = handle outer_body() with {\n\
               E1.op1(k) => k(0),\n\
               E2.op2(k) => k(0),\n\
               return(v) => v + 100,\n\
               };\n\
               perform IO.println(int_to_string(outer));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(
        src,
        "task_111d_nested_handle_inner_discharge_does_not_leak_to_outer",
    );
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "1090\n",
        "Plan D Task 111d snapshot/restore: inner handle's \
         (value=99, tag=DISCHARGED) terminal must NOT leak into the \
         outer handle's exit-tag query. Outer body returns naturally \
         (`inner * 10 = 990`); outer's exit must read DONE (the \
         restored snapshot) and dispatch the return arm (`v + 100 = \
         1090`). Pre-fix output is `99` (leaked DISCHARGED + leaked \
         inner value). stderr={stderr:?}"
    );
}

/// Pattern C branch-leaf perform extension: `perform` inside a branch
/// body. The body has a prefix perform (`State.get`), then a branched
/// tail where EACH branch contains `let _ = perform State.set(...);`
/// before its leaf. The existing classifier rejects `Stmt::Let` with
/// `Perform` RHS inside branch leaves; this test pins the fix.
///
/// Trace: helper(3) → S.get()=0, branch n!=0 → S.set(3), recurse
/// helper(2) → S.get()=3, branch n!=0 → S.set(2), recurse
/// helper(1) → S.get()=2, branch n!=0 → S.set(1), recurse
/// helper(0) → S.get()=1, branch n==0 → S.set(42), pure leaf 99.
/// State ends at 42. comp() → S.get() = 42. Output: "42".
#[test]
fn pattern_c_in_branch_perform_state_threading_returns_42() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect S resumes: many {\n\
               get: () -> Int,\n\
               set: (Int) -> Int,\n\
               }\n\
               \n\
               fn helper(n: Int) -> Int ![S] {\n\
               let _x: Int = perform S.get();\n\
               if n == 0 {\n\
               let _s0: Int = perform S.set(42);\n\
               99\n\
               } else {\n\
               let _s1: Int = perform S.set(n);\n\
               helper(n - 1)\n\
               }\n\
               }\n\
               \n\
               fn run_state(initial: Int, body: () -> Int ![S]) -> Int ![] {\n\
               let state_fn: (Int) -> Int ![] = handle body() with {\n\
               return(v) => fn (s: Int) -> Int ![] => v,\n\
               S.get(k) => fn (s: Int) -> Int ![] => k(s)(s),\n\
               S.set(arg, k) => fn (s: Int) -> Int ![] => k(arg)(arg),\n\
               };\n\
               state_fn(initial)\n\
               }\n\
               \n\
               fn comp() -> Int ![S] {\n\
               let _y: Int = helper(3);\n\
               let v: Int = perform S.get();\n\
               v\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let result: Int = run_state(0, comp);\n\
               perform IO.println(int_to_string(result));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "pattern_c_in_branch_perform");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "42\n",
        "Pattern C in-branch perform: helper(3) recurses with State.set \
         inside each branch. Final S.set(42) at base case. comp() reads \
         42 via S.get(). Wrong outputs surface a classifier or branch-chain \
         emit regression. stderr={stderr:?}"
    );
}

