// ===== list_sort =====

/// Helper: print a list of ints space-separated, terminated with newline.
fn int_list_print_helper() -> &'static str {
    "fn print_ints(xs: List[Int]) -> Int ![IO] {\n  \
       match xs {\n    \
         Nil => 0,\n    \
         Cons(h, t) => {\n      \
           perform IO.println(int_to_string(h));\n      \
           print_ints(t)\n    \
         },\n  \
       }\n\
     }\n"
}

