/// P20-backstop case 1 — multiple branched-perform stmts in series.
/// `lift_trailing_branched_stmt_to_tail` only lifts the LAST branched
/// stmt; the first one stays in stmts position and would silently
/// miscompile under Sync ABI on multi-shot resumes. The codegen-entry
/// `p20_silent_miscompile_check` rejects this shape with E0149 before
/// any object code is emitted.
#[test]
fn p20_backstop_rejects_multiple_branched_stmts_in_series() {
    let src = "import std.io\n\
               use std.io.{IO};\n\
               effect Choose resumes: many { pick: (Int, Int) -> Int }\n\
               fn pairs() -> Int ![Choose, IO] {\n\
                 let a: Int = perform Choose.pick(1, 6);\n\
                 let b: Int = perform Choose.pick(1, 6);\n\
                 match a == 7 {\n\
                   true => perform IO.println(\"seven\"),\n\
                   false => (),\n\
                 };\n\
                 match b == 7 {\n\
                   true => perform IO.println(\"seven\"),\n\
                   false => (),\n\
                 };\n\
                 0\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let _r: Int = handle pairs() with {\n\
                   Choose.pick(low, high, k) => {\n\
                     let r1: Int = k(1);\n\
                     let r2: Int = k(2);\n\
                     0\n\
                   },\n\
                 };\n\
                 0\n\
               }\n";
    assert_compile_fails_with_code(
        src,
        "E0149",
        &["pairs", "branched expression in statement position"],
        "p20_backstop_multiple_branched_stmts",
    );
}

/// P20-backstop case 2 — branched-perform stmt followed by a
/// perform-bearing tail. `lift_trailing_branched_stmt_to_tail` bails
/// (its `!expr_contains_perform(tail)` gate fails), so the branched
/// stmt stays in stmts position. After tail-perform normalization the
/// body has `[..., Stmt::Expr(Match), Stmt::Let __tail_perform_v]`,
/// fails every Cps classifier, falls through to Sync ABI, and would
/// silently miscompile on multi-shot resumes. E0149 fires.
#[test]
fn p20_backstop_rejects_branched_stmt_with_perform_tail() {
    let src = "import std.io\n\
               use std.io.{IO};\n\
               effect Choose resumes: many { pick: (Int, Int) -> Int }\n\
               fn helper() -> Int ![Choose, IO] {\n\
                 let a: Int = perform Choose.pick(1, 6);\n\
                 match a == 7 {\n\
                   true => perform IO.println(\"seven\"),\n\
                   false => (),\n\
                 };\n\
                 perform Choose.pick(1, 1)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let _r: Int = handle helper() with {\n\
                   Choose.pick(low, high, k) => {\n\
                     let r1: Int = k(1);\n\
                     let r2: Int = k(2);\n\
                     0\n\
                   },\n\
                 };\n\
                 0\n\
               }\n";
    assert_compile_fails_with_code(
        src,
        "E0149",
        &["helper", "branched expression in statement position"],
        "p20_backstop_branched_stmt_with_perform_tail",
    );
}

/// Plan A (PR #119 review #2a) — non-trivial Binary in perform args.
/// Pre-fix this triggered a codegen panic at the chained-let-yield
/// body-emit's `body_first_step` extraction (`unreachable!()` at the
/// `Stmt::Let` Binary-value match arm) because the body emit walked
/// `f.body` un-rewritten while ABI selection saw the elaborator-
/// inlined form. The Phase 2 re-rewrite fix at the body emit site
/// closes the gap; this test pins it.
#[test]
fn multi_shot_post_perform_tail_nontrivial_perform_args() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               effect Choose resumes: many { choose: (Int) -> Int }\n\
               fn helper(seed: Int, factor: Int) -> Int ![Choose, IO] {\n\
                 let x: Int = perform Choose.choose(seed + factor * factor);\n\
                 perform IO.println(int_to_string(x));\n\
                 x * 1000\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let total: Int = handle helper(5, 3) with {\n\
                   Choose.choose(arg, k) => {\n\
                     let r1: Int = k(7);\n\
                     let r2: Int = k(11);\n\
                     r1 * 100 + r2\n\
                   },\n\
                 };\n\
                 perform IO.println(int_to_string(total));\n\
                 0\n\
               }\n";
    let (stdout, stderr, code) =
        compile_and_run(src, "multi_shot_post_perform_tail_nontrivial_perform_args");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "7\n11\n711000\n",
        "Plan A: helper's perform-arg expression `seed + factor * factor` \
         elaborator-hoists into a `$elab_t*` chain; the Phase 2 rewriter inlines \
         them back so the chained-let-yield classifier accepts. Per-resume \
         body execution prints arg_i and returns arg_i*1000; arm combine \
         700000 + 11000 = 711000. stderr={stderr:?}"
    );
}

/// Plan A (PR #119 review #2b) — Cps user fn call inside perform args.
/// The args-purity relaxation (`expr_is_pure → !expr_contains_perform`)
/// permits Calls in args; the chain step's Middle synth-cont's emit
/// lowers them via `lowerer.lower_expr`, which routes Cps user fn calls
/// through `lower_call`'s existing Sync→Cps interop wrapper. This test
/// exercises that path.
#[test]
fn multi_shot_post_perform_tail_cps_call_in_args() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               effect Tag { mark: () -> Int }\n\
               fn marked_id(x: Int) -> Int ![Tag] {\n\
                 let _t: Int = perform Tag.mark();\n\
                 x\n\
               }\n\
               effect Choose resumes: many { choose: (Int) -> Int }\n\
               fn helper(seed: Int) -> Int ![Choose, Tag, IO] {\n\
                 let x: Int = perform Choose.choose(marked_id(seed));\n\
                 perform IO.println(int_to_string(x));\n\
                 x * 100\n\
               }\n\
               fn run_tag(s: Int) -> Int ![Choose, IO] {\n\
                 handle helper(s) with {\n\
                   Tag.mark(k) => k(1),\n\
                 }\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let total: Int = handle run_tag(5) with {\n\
                   Choose.choose(arg, k) => {\n\
                     let r1: Int = k(7);\n\
                     let r2: Int = k(11);\n\
                     r1 + r2\n\
                   },\n\
                 };\n\
                 perform IO.println(int_to_string(total));\n\
                 0\n\
               }\n";
    let (stdout, stderr, code) =
        compile_and_run(src, "multi_shot_post_perform_tail_cps_call_in_args");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "7\n11\n1800\n",
        "Plan A: `marked_id(seed)` is a Cps user fn call inside the multi-shot \
         perform's args; routes through Sync→Cps interop synchronously. The \
         args eval ONCE at the perform site (not per resume) — Tag.mark() \
         fires once with seed=5. Per-resume body execution: x=7 prints 7 \
         and returns 700; x=11 prints 11 and returns 1100; arm combine \
         r1+r2 = 1800. stderr={stderr:?}"
    );
}

/// Plan A (PR #119 review #2c) — mid-body discard `Stmt::Perform` whose
/// op has a non-Unit return type. The Phase 2 rewriter's
/// `rewrite_perform_stmts_as_lets` synthesizes a let with the op's
/// actual return type (looked up via the effects registry), not a
/// hardcoded Unit. This test exercises a Stmt::Perform of an `Int`-
/// returning op (`Counter.tick`) whose result is discarded by source
/// semantics.
#[test]
fn multi_shot_post_perform_tail_nonunit_discard_perform() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               effect Counter { tick: () -> Int }\n\
               effect Choose resumes: many { choose: (Int) -> Int }\n\
               fn helper(seed: Int) -> Int ![Choose, Counter, IO] {\n\
                 let x: Int = perform Choose.choose(seed);\n\
                 perform Counter.tick();\n\
                 perform IO.println(int_to_string(x));\n\
                 x * 1000\n\
               }\n\
               fn run_counter(s: Int) -> Int ![Choose, IO] {\n\
                 handle helper(s) with {\n\
                   Counter.tick(k) => k(99),\n\
                 }\n\
               }\n\
               fn main() -> Int ![IO] {\n\
                 let total: Int = handle run_counter(5) with {\n\
                   Choose.choose(arg, k) => {\n\
                     let r1: Int = k(7);\n\
                     let r2: Int = k(11);\n\
                     r1 * 100 + r2\n\
                   },\n\
                 };\n\
                 perform IO.println(int_to_string(total));\n\
                 0\n\
               }\n";
    let (stdout, stderr, code) =
        compile_and_run(src, "multi_shot_post_perform_tail_nonunit_discard_perform");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "7\n11\n711000\n",
        "Plan A: `perform Counter.tick()` is a discard-Stmt::Perform with \
         non-Unit return type (Int). The rewriter synthesizes \
         `let __perform_unit_<idx>: Int = perform Counter.tick()` rather \
         than hardcoding Unit. Per-resume body execution: x=7 prints 7 \
         and returns 7000; x=11 prints 11 and returns 11000; arm combine \
         700000 + 11000 = 711000. stderr={stderr:?}"
    );
}

// ===== Pattern C SumType dispatch — lambda-of-state runtime correctness =====

/// Plotkin-style handler with sum-type match body (IntList). The
/// handler's return arm returns final state (`s`), not the body
/// value — `return(v) => fn(s) => s`. count_elements over a
/// 5-element list increments state at each Cons; final state = 5.
/// NOT the literal P19 prompt (which uses `return(v) => fn(_) => v`).
#[test]
fn lambda_of_state_sum_type_state_threading_returns_5() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect State resumes: many { get: () -> Int, set: (Int) -> Int }\n\
               type IntList = | Nil | Cons(Int, IntList)\n\
               fn count_elements(xs: IntList) -> Int ![State, IO] {\n\
               match xs {\n\
               Nil => 0,\n\
               Cons(_, rest) => {\n\
               let cur: Int = perform State.get();\n\
               let _: Int = perform State.set(cur + 1);\n\
               count_elements(rest)\n\
               },\n\
               }\n\
               }\n\
               fn run_state(initial: Int, comp: () -> Int ![State, IO]) -> Int ![IO] {\n\
               let runner: (Int) -> Int ![IO] = handle comp() with {\n\
               return(v) => fn (s: Int) -> Int ![IO] => s,\n\
               State.get(k) => fn (s: Int) -> Int ![IO] => k(s)(s),\n\
               State.set(s2, k) => fn (_s: Int) -> Int ![IO] => k(s2)(s2),\n\
               };\n\
               runner(initial)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let xs: IntList = Cons(10, Cons(20, Cons(30, Cons(40, Cons(50, Nil)))));\n\
               let final_count: Int = run_state(0, fn () -> Int ![State, IO] => count_elements(xs));\n\
               perform IO.println(int_to_string(final_count));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "lambda_of_state_sum_type_state_threading");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "5\n",
        "Lambda-of-state state threading: count_elements over 5-element \
         IntList, handler return arm returns final state s=5. Wrong \
         output means SumType Pattern C dispatch or handler arm \
         threading is broken. stderr={stderr:?}"
    );
}

/// Literal P19 handler shape: `return(v) => fn(_) => v` returns the
/// body's terminal value, not the final state. count_elements' base
/// case is `Nil => 0`, so the output is 0. This test verifies the
/// SumType dispatch produces the semantically correct result under
/// the canonical Plotkin encoding where return discards state.
#[test]
fn lambda_of_state_literal_p19_body_value_returns_0() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect State resumes: many { get: () -> Int, set: (Int) -> Int }\n\
               type IntList = | Nil | Cons(Int, IntList)\n\
               fn count_elements(xs: IntList) -> Int ![State, IO] {\n\
               match xs {\n\
               Nil => 0,\n\
               Cons(_, rest) => {\n\
               let cur: Int = perform State.get();\n\
               let _: Int = perform State.set(cur + 1);\n\
               count_elements(rest)\n\
               },\n\
               }\n\
               }\n\
               fn run_state(initial: Int, comp: () -> Int ![State, IO]) -> Int ![IO] {\n\
               let runner: (Int) -> Int ![IO] = handle comp() with {\n\
               return(v) => fn (_s: Int) -> Int ![IO] => v,\n\
               State.get(k) => fn (s: Int) -> Int ![IO] => k(s)(s),\n\
               State.set(s2, k) => fn (_s: Int) -> Int ![IO] => k(s2)(s2),\n\
               };\n\
               runner(initial)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let xs: IntList = Cons(10, Cons(20, Cons(30, Cons(40, Cons(50, Nil)))));\n\
               let result: Int = run_state(0, fn () -> Int ![State, IO] => count_elements(xs));\n\
               perform IO.println(int_to_string(result));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "lambda_of_state_literal_p19");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "0\n",
        "Literal P19 shape: return(v) => fn(_s) => v returns body terminal \
         value (0 from Nil base case), not final state. This is the \
         semantically correct output per Plotkin's encoding. stderr={stderr:?}"
    );
}

/// 3-arm sum-type match: exercises N-arm SumType dispatch with N>2.
/// Shape: `Red | Green | Blue` enum where Green and Blue arms
/// perform State.set, Red arm is pure. Handler returns final state.
#[test]
fn lambda_of_state_three_arm_sum_type_dispatch() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect State resumes: many { get: () -> Int, set: (Int) -> Int }\n\
               type Color = | Red | Green | Blue\n\
               fn process(c: Color) -> Int ![State] {\n\
               match c {\n\
               Red => 0,\n\
               Green => {\n\
               let cur_g: Int = perform State.get();\n\
               let _g: Int = perform State.set(cur_g + 10);\n\
               1\n\
               },\n\
               Blue => {\n\
               let cur_b: Int = perform State.get();\n\
               let _b: Int = perform State.set(cur_b + 100);\n\
               2\n\
               },\n\
               }\n\
               }\n\
               fn run_state(initial: Int, comp: () -> Int ![State]) -> Int ![] {\n\
               let runner: (Int) -> Int ![] = handle comp() with {\n\
               return(v) => fn (s: Int) -> Int ![] => s,\n\
               State.get(k) => fn (s: Int) -> Int ![] => k(s)(s),\n\
               State.set(s2, k) => fn (_s: Int) -> Int ![] => k(s2)(s2),\n\
               };\n\
               runner(initial)\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let r1: Int = run_state(0, fn () -> Int ![State] => process(Green));\n\
               let r2: Int = run_state(0, fn () -> Int ![State] => process(Blue));\n\
               let r3: Int = run_state(0, fn () -> Int ![State] => process(Red));\n\
               perform IO.println(int_to_string(r1));\n\
               perform IO.println(int_to_string(r2));\n\
               perform IO.println(int_to_string(r3));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "lambda_of_state_three_arm");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "10\n100\n0\n",
        "3-arm sum-type dispatch: Green sets state+10 (final=10), \
         Blue sets state+100 (final=100), Red is pure (final=0). \
         Exercises N>2 arm SumType dispatch. stderr={stderr:?}"
    );
}

/// Sum-type match with CPS calls in arm stmts must fall through to
/// standard-tail path (not SumType dispatch). The g5 eval pattern:
/// DivE arm has recursive CPS calls to eval before performs. Uses
/// polymorphic run_state_poly, Raise/catch from the original g5 test.
#[test]
fn lambda_of_state_sum_type_with_cps_calls_falls_through() {
    let src = "import std.int\n\
               import std.raise\n\
               import std.result\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               use std.raise.{ArithError, Raise, catch, raise};\n\
               use std.result.{Err, Ok, Result};\n\
               \n\
               effect State resumes: many { get: () -> Int, set: (Int) -> Int }\n\
               \n\
               fn run_state_poly[A](initial: Int, body: () -> A ![State | e]) -> A ![| e] {\n\
               let state_fn: (Int) -> A ![| e] = handle body() with {\n\
               return(v) => fn (s: Int) -> A ![| e] => v,\n\
               State.get(k) => fn (s: Int) -> A ![| e] => k(s)(s),\n\
               State.set(arg, k) => fn (s: Int) -> A ![| e] => k(arg)(arg),\n\
               };\n\
               state_fn(initial)\n\
               }\n\
               \n\
               type Expr = | IntE(Int) | DivE(Expr, Expr)\n\
               \n\
               fn eval(e: Expr) -> Int ![Raise[String], State, ArithError, IO] {\n\
               match e {\n\
               IntE(i) => i,\n\
               DivE(e1, e2) => {\n\
               let x: Int = eval(e1);\n\
               let y: Int = eval(e2);\n\
               let cur: Int = perform State.get();\n\
               let _: Int = perform State.set(cur + 1);\n\
               perform IO.println(\"tick\");\n\
               if y == 0 {\n\
               let _r: Int = raise(\"divide by zero\");\n\
               _r\n\
               } else {\n\
               x / y\n\
               }\n\
               },\n\
               }\n\
               }\n\
               \n\
               fn main() -> Int ![IO, ArithError] {\n\
               let prog: Expr = DivE(DivE(IntE(16), IntE(2)), IntE(3));\n\
               let r: Result[Int, String] = catch(fn () -> Int ![Raise[String], ArithError, IO] => run_state_poly(0, fn () -> Int ![Raise[String], State, ArithError, IO] => eval(prog)));\n\
               match r {\n\
               Ok(v) => perform IO.println(int_to_string(v)),\n\
               Err(m) => perform IO.println(m),\n\
               };\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "lambda_of_state_sum_type_cps_calls");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "tick\ntick\n2\n",
        "Sum-type match with CPS calls (eval) in DivE arm must fall \
         through to standard-tail (not SumType dispatch). DivE(DivE(16,2),3): \
         two DivE arms each print tick, handler return(v)=>fn(s)=>v \
         returns 16/2/3=2. Wrong output means SumType dispatch was \
         incorrectly applied to arms with CPS calls. stderr={stderr:?}"
    );
}

// ===== Multi-shot Cps-call-as-tail (Plan D Task 112e — runtime fix) =====

/// Multi-shot body with 2 performs + CPS-call-as-tail. Previously
/// rejected by E0221 (PR #122) because the chain machinery's
/// `OUTER_POST_ARM_K_DROP` discipline dropped the chain push per
/// resume, underflowing the stack and preventing the trampoline's
/// Done-pop from advancing the outer multi-shot to k(N+1). Plan D
/// Task 112e refined the drop to fire ONLY for recursive Cps→Cps
/// tail calls (callee == enclosing fn), leaving non-recursive
/// Cps-call-as-tail composition intact across multi-shot resumes.
///
/// Oracle: full enumeration of all 36 (a, b) pairs from `pick(1, 6)`,
/// printing the six matching pairs `16, 25, 34, 43, 52, 61`. Pre-fix
/// only the first inner resume's matching pair fired (or, depending
/// on classifier path, no output at all). Post-fix all six fire.
#[test]
fn cps_call_as_tail_in_multi_shot_runtime_correct() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect Choose resumes: many { pick: (Int, Int) -> Int }\n\
               \n\
               fn report(a: Int, b: Int) -> Int ![IO] {\n\
               match a + b == 7 {\n\
               true => { perform IO.println(int_to_string(a * 10 + b)); 0 },\n\
               false => 0,\n\
               }\n\
               }\n\
               \n\
               fn pairs() -> Int ![Choose, IO] {\n\
               let a: Int = perform Choose.pick(1, 6);\n\
               let b: Int = perform Choose.pick(1, 6);\n\
               report(a, b)\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let total: Int = handle pairs() with {\n\
               Choose.pick(low, high, k) => {\n\
               let r1: Int = k(1); let r2: Int = k(2); let r3: Int = k(3);\n\
               let r4: Int = k(4); let r5: Int = k(5); let r6: Int = k(6);\n\
               r1 + r2 + r3 + r4 + r5 + r6\n\
               },\n\
               };\n\
               total\n\
               }\n";
    let (stdout, stderr, code) =
        compile_and_run(src, "cps_call_as_tail_multi_shot_runtime_correct");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "16\n25\n34\n43\n52\n61\n",
        "Multi-shot Cps-call-as-tail enumerates all matching pairs. \
         stderr={stderr:?}"
    );
}

