/// Regression: outer sum-type match arm binds a name (e.g. `t` in
/// `Cons(_, t)`); the arm body is a *nested* branched-cps expr (an
/// `if`/`match`) whose Cps branch references the outer-arm binding.
/// Before the seed-branch propagation fix, the synth-cont's closure
/// record was built without the outer arm's pattern bindings — the
/// `Nested` descent in `collect_branch_chain_allocs::seed_branch_work`
/// dropped them — so emit of the inner BranchLeafFinal tail (the
/// recursive `rec(t)`) tripped `lower_expr`'s env lookup with
/// `internal error: codegen: unknown ident t`.
///
/// The minimal trigger requires:
/// (1) outer sum-type match arm with a binding,
/// (2) arm body is itself a branched expr (here `if true { ... } else { ... }`),
/// (3) at least one inner branch has a `perform` before the tail,
/// (4) the inner branch's tail (the BranchLeafFinal) references the
///     outer arm's binding.
#[test]
fn pattern_c_outer_arm_binding_visible_to_nested_perform_branch() {
    let src = "import std.list\n\
               import std.io\n\
               use std.io.{IO};\n\
               use std.list.{Cons, List, Nil};\n\
               \n\
               fn rec(lst: List[Int]) -> Int ![IO] {\n\
                 match lst {\n\
                   Nil => 0,\n\
                   Cons(_, t) => if true {\n\
                     perform IO.println(\"a\");\n\
                     rec(t)\n\
                   } else {\n\
                     rec(t)\n\
                   },\n\
                 }\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
                 rec(Cons(1, Cons(2, Nil)))\n\
               }\n\
               ";
    let (stdout, stderr, code) = compile_and_run(src, "pattern_c_outer_arm_binding_nested_perform");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(
        stdout, "a\na\n",
        "Outer Cons(_, t) binding must reach the inner perform branch's \
         tail call rec(t); two list elements each take the perform branch. \
         stderr={stderr:?}"
    );
}

/// Multi-level nesting variant of the previous regression: outer
/// `match` arm binds `t`; arm body is an `if` (Nested level 1); the
/// `if`'s then-branch is itself a `match` (Nested level 2); one inner
/// `match` arm binds `et` AND has a `perform` before the tail; the
/// tail references *both* the outer arm's binding (`t`) and the inner
/// arm's binding (`et`). Validates `parent_bindings` accumulating
/// through more than one Nested descent.
#[test]
fn pattern_c_outer_arm_binding_visible_through_two_nested_levels() {
    let src = "import std.list\n\
               import std.io\n\
               use std.io.{IO};\n\
               use std.list.{Cons, List, Nil};\n\
               \n\
               fn rec(lst: List[Int], extra: List[Int]) -> Int ![IO] {\n\
                 match lst {\n\
                   Nil => 0,\n\
                   Cons(h, t) => if h > 0 {\n\
                     match extra {\n\
                       Nil => {\n\
                         perform IO.println(\"nil\");\n\
                         rec(t, extra)\n\
                       },\n\
                       Cons(_, et) => {\n\
                         perform IO.println(\"cons\");\n\
                         rec(t, et)\n\
                       },\n\
                     }\n\
                   } else {\n\
                     rec(t, extra)\n\
                   },\n\
                 }\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
                 rec(Cons(1, Cons(2, Nil)), Cons(10, Nil))\n\
               }\n\
               ";
    let (stdout, stderr, code) =
        compile_and_run(src, "pattern_c_outer_arm_binding_two_nested_levels");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // Step 1: h=1 (>0), extra=Cons(10, Nil) → inner Cons(_, et) arm
    //         prints "cons", recurses with (t=Cons(2, Nil), et=Nil).
    // Step 2: h=2 (>0), extra=Nil → inner Nil arm prints "nil",
    //         recurses with (t=Nil, extra=Nil).
    // Step 3: lst=Nil → returns 0.
    assert_eq!(
        stdout, "cons\nnil\n",
        "two-level nesting must propagate outer arm binding `t` AND inner \
         arm binding `et` into the perform branch's synth-cont closure \
         record. stderr={stderr:?}"
    );
}

/// Category C #1 — minimal repro: pure `let` in a match-arm body, referenced
/// from a second `perform` in the same arm. Before the fix this panicked
/// with "codegen: unknown ident `name`" because BranchedCpsLeaf::PerformChain
/// captures did not include arm-body inner_tail_prefix_lets.
///
/// Uses `IO.println` (not `IO.print`) because Rust's stdout is line-buffered
/// — bytes written without a trailing newline stay buffered and the sigil
/// binary's C-main exit path doesn't invoke Rust's atexit flush, so a final
/// `IO.print`-only program produces empty captured stdout. The newline
/// forces a per-line flush. The semantic test (pre-yield let reachable from
/// a later perform) is independent of the newline.
#[test]
fn branch_chain_pure_let_referenced_by_later_perform_minimal() {
    let source = "import std.io\n\
                  use std.io.{IO};\n\
                  fn print_names(b: Bool) -> Int ![IO] {\n\
                  match b {\n\
                  true => 0,\n\
                  false => {\n\
                  let name: String = \"x\";\n\
                  perform IO.println(\"first\");\n\
                  perform IO.println(name);\n\
                  0\n\
                  },\n\
                  }\n\
                  }\n\
                  fn main() -> Int ![IO] { print_names(false) }\n";
    let (stdout, stderr, code) = compile_and_run(source, "branch_chain_pure_let_minimal");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(stdout, "first\nx\n", "stdout; stderr={stderr:?}");
}

/// Category C #2 — pure-fn RHS (mirrors H02's `let is_valid: Bool =
/// validate_json_number(input)` shape). Confirms the captured pure-let
/// value reaches every step in the chain. Uses `IO.println` for the same
/// buffering reason as the minimal repro above.
///
/// Note on name: an earlier version of this test was named
/// `..._runs_once` and claimed to prove single-evaluation of `double(n)`.
/// The assertion `stdout == "6\n:\n6\n"` does not actually distinguish
/// single-eval from double-eval because `double(n) = n + n` is pure and
/// idempotent — both eval counts return 6. A true single-eval probe
/// would require a side-effecting RHS, but adding `![IO]` to `double`
/// makes it a CPS-color user fn that the `classify_branched_cps_tail_branch`
/// `is_supported` check rejects (the arm body would no longer classify
/// as PerformChain), so the test would no longer exercise this code
/// path. Single-evaluation is guaranteed structurally by the codegen:
/// `pre_yield_pure_lets` are lowered ONCE by the `for stmt in
/// leaf_stmts` loop at codegen.rs:17856-17867 (a single
/// `lower_expr(&l.value)` + `env.insert(l.name, v)` per stmt, breaking
/// at the first perform) and reused via captures; the FINAL step's
/// `tail_prefix_lets` only contains post-yield lets, so it doesn't
/// re-evaluate pre-yield RHSs.
#[test]
fn branch_chain_pure_let_with_fn_rhs_value_propagates() {
    let source = "import std.int\n\
                  import std.io\n\
                  use std.int.{int_to_string};\n\
                  use std.io.{IO};\n\
                  fn double(n: Int) -> Int ![] { n + n }\n\
                  fn print_doubled(n: Int) -> Int ![IO] {\n\
                  match n {\n\
                  0 => 0,\n\
                  _ => {\n\
                  let d: Int = double(n);\n\
                  perform IO.println(int_to_string(d));\n\
                  perform IO.println(\":\");\n\
                  perform IO.println(int_to_string(d));\n\
                  0\n\
                  },\n\
                  }\n\
                  }\n\
                  fn main() -> Int ![IO] { print_doubled(3) }\n";
    let (stdout, stderr, code) = compile_and_run(source, "branch_chain_pure_let_fn_rhs");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // d = 6, captured into branch_captures, observed in both perform args.
    assert_eq!(stdout, "6\n:\n6\n", "stdout; stderr={stderr:?}");
}

/// Category C #3 — Cons-arm shape (mirrors H04's `Cons(head, tail) => { let
/// name = entry_name(head); ... print twice ... }`). Confirms the fix works
/// when the pure-let RHS depends on an arm-bound pattern variable. Uses
/// `IO.println` for the same buffering reason as the minimal repro above.
///
/// `take_label` is an identity helper (returns its String arg unchanged);
/// its purpose is to make the let RHS a `Call` with `arm-binding-as-arg`
/// shape so the test exercises pre-yield RHSs that depend on an arm
/// pattern binding, not a String literal.
#[test]
fn branch_chain_pure_let_in_cons_arm_uses_arm_binding() {
    let source = "import std.io\n\
                  import std.list\n\
                  use std.io.{IO};\n\
                  use std.list.{Cons, List, Nil};\n\
                  fn take_label(s: String) -> String ![] { s }\n\
                  fn show(xs: List[String]) -> Int ![IO] {\n\
                  match xs {\n\
                  Nil => 0,\n\
                  Cons(head, _) => {\n\
                  let label: String = take_label(head);\n\
                  perform IO.println(\"[\");\n\
                  perform IO.println(label);\n\
                  perform IO.println(\"]\");\n\
                  0\n\
                  },\n\
                  }\n\
                  }\n\
                  fn main() -> Int ![IO] { show(Cons(\"hi\", Nil)) }\n";
    let (stdout, stderr, code) = compile_and_run(source, "branch_chain_cons_arm_pure_let");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    assert_eq!(stdout, "[\nhi\n]\n", "stdout; stderr={stderr:?}");
}

/// Category C #4 — post-yield pure let evaluated by the FINAL step.
/// Companion to tests #1-#3 (which exercise the pre-yield path the
/// split-fix promotes to captures). This pins the OTHER arm of the
/// split: a pure let bound AFTER all yields, its RHS evaluated at the
/// FINAL step's `inner_tail_prefix_lets` loop, its value referenced
/// from the FINAL step's tail (Pure leaf). The assertion observes
/// `x` directly via the chain's return value — `show` returns `x`
/// and `main` prints it, so any miscomputation in the FINAL step's
/// post-yield-let evaluation (uninitialized stack, wrong env slot,
/// sign-extension bug, ICE on the tail's `Ident("x")` lookup) trips
/// the assertion.
///
/// Scope caveat: this test deliberately does NOT reference the
/// post-yield let from an EARLIER perform-arg in the chain. That
/// shape (Middle step lowering a perform-arg that names a post-yield
/// pure let) is a separate codegen bug — the post-yield let isn't in
/// any earlier Middle step's env (its RHS may depend on later
/// perform-result `prior_bindings` that don't exist yet at the
/// Middle step) and lowering would trip the same "unknown ident" ICE
/// this PR closes for the pre-yield case. Out of scope here; if/when
/// it surfaces in the baseline campaign, it's a follow-up plan.
#[test]
fn branch_chain_post_yield_pure_let_evaluated_by_final_step() {
    let source = "import std.int\n\
                  import std.io\n\
                  use std.int.{int_to_string};\n\
                  use std.io.{IO};\n\
                  fn show(b: Bool) -> Int ![IO] {\n\
                  match b {\n\
                  true => 0,\n\
                  false => {\n\
                  perform IO.println(\"a\");\n\
                  perform IO.println(\"b\");\n\
                  let x: Int = 5;\n\
                  x\n\
                  },\n\
                  }\n\
                  }\n\
                  fn main() -> Int ![IO] {\n\
                  let r: Int = show(false);\n\
                  perform IO.println(int_to_string(r));\n\
                  0\n\
                  }\n";
    let (stdout, stderr, code) = compile_and_run(source, "branch_chain_post_yield_let");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // "a\nb\n" from the chain's perforns, "5\n" from main printing the
    // value FINAL flowed through caller_k_pair. Any wrong value for `x`
    // surfaces directly in the third line.
    assert_eq!(stdout, "a\nb\n5\n", "stdout; stderr={stderr:?}");
}

/// Category C #5 — mixed pre/post-yield lets in the same arm. The PR's
/// load-bearing change is the SPLIT between `pre_yield_pure_lets`
/// (promoted to `branch_captures`, visible to every step via
/// synth_closure_ptr) and `inner_tail_prefix_lets` (left on the FINAL
/// step's role, evaluated locally there). Tests #1-#3 exercise only
/// pre-yield; test #4 exercises only post-yield. This one exercises
/// BOTH in a single arm — the only configuration that catches a
/// split bug where the bags cross, e.g. an off-by-one when
/// `seen_yield` flips, a FINAL emit accidentally evaluating
/// pre-yield names, or a capture-store loop picking up post-yield
/// names.
///
/// Shape: `pre` is used in a Middle perform-arg (proves capture
/// path); `post` is used in the FINAL tail (proves
/// inner_tail_prefix_lets path); `pre + post` in the tail proves
/// both values are live in the FINAL step's env at the same time.
#[test]
fn branch_chain_pre_and_post_yield_lets_in_same_arm() {
    let source = "import std.int\n\
                  import std.io\n\
                  use std.int.{int_to_string};\n\
                  use std.io.{IO};\n\
                  fn show(b: Bool) -> Int ![IO] {\n\
                  match b {\n\
                  true => 0,\n\
                  false => {\n\
                  let pre: Int = 1;\n\
                  perform IO.println(int_to_string(pre));\n\
                  perform IO.println(\"mid\");\n\
                  let post: Int = 2;\n\
                  pre + post\n\
                  },\n\
                  }\n\
                  }\n\
                  fn main() -> Int ![IO] {\n\
                  let r: Int = show(false);\n\
                  perform IO.println(int_to_string(r));\n\
                  0\n\
                  }\n";
    let (stdout, stderr, code) = compile_and_run(source, "branch_chain_mixed_pre_post");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // pre=1 promoted to captures and read in P0's `int_to_string(pre)`
    // arg (via outer body emit's pre-yield-let env-insert). post=2
    // evaluated by FINAL's inner_tail_prefix_lets loop. Tail `pre +
    // post` = 3, flowed through caller_k_pair to main.
    assert_eq!(stdout, "1\nmid\n3\n", "stdout; stderr={stderr:?}");
}

/// 2026-05-04 return-arm-via-args lift Stage 5 — re-entrancy regression
/// gate. Nests two `handle` expressions whose body fns each have
/// distinct return arms. The TLS approach masked outer with inner via
/// stack push-on-top discipline (LIFO); the args_ptr-passing approach
/// achieves the same via per-call args_ptr — each body fn's args_ptr
/// trailing slots carry its own handle's return arm.
///
/// Invariant: the inner body's natural-exit fires the INNER return arm
/// (+200), and the inner handle's overall value flows through the
/// OUTER return arm (+100). The outer return arm must NOT fire on the
/// inner body's natural-exit, and the inner return arm must NOT fire
/// on the outer body's natural-exit.
///
/// Pre-lift: this test pinned the TLS push-on-top discipline. Post-
/// lift (Stage 3a body-fn natural-exit reads from args_ptr): pins the
/// per-call args_ptr propagation discipline for the body-fn dispatch
/// site. Sites 2-4 (synth-cont natural exits) still consult TLS in the
/// current PR — the test would catch any future regression where the
/// per-call discipline diverges from the TLS push-on-top.
#[test]
fn return_arm_via_args_nested_handles_distinct_arms() {
    let src = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               \n\
               effect Outer { signal: () -> Int }\n\
               effect Inner { signal: () -> Int }\n\
               \n\
               fn inner_body() -> Int ![Inner] {\n\
               perform Inner.signal()\n\
               }\n\
               \n\
               fn outer_body() -> Int ![Outer] {\n\
               let inner_wrapped: Int = handle inner_body() with {\n\
               Inner.signal(k) => k(7),\n\
               return(v) => v + 200,\n\
               };\n\
               let outer_signal: Int = perform Outer.signal();\n\
               inner_wrapped + outer_signal\n\
               }\n\
               \n\
               fn main() -> Int ![IO] {\n\
               let result: Int = handle outer_body() with {\n\
               Outer.signal(k) => k(11),\n\
               return(v) => v + 100,\n\
               };\n\
               perform IO.println(int_to_string(result));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(src, "return_arm_via_args_nested_handles");
    assert_eq!(code, 0, "exit code; stderr={stderr:?}");
    // Trace:
    //  inner_body() perform Inner.signal → arm k(7) → inner_body returns 7
    //  inner return arm: 7 + 200 = 207  (inner_result)
    //  outer_body's `perform Outer.signal` → arm k(11) → outer_result = 11
    //  outer_body returns inner_result + outer_result = 207 + 11 = 218
    //  outer return arm: 218 + 100 = 318  (result)
    //  print_list "318\n"
    assert_eq!(
        stdout, "318\n",
        "Nested handles with distinct return arms: inner return arm wraps \
         inner body's tail (+200), outer return arm wraps outer body's \
         tail (+100); cross-pollination would surface as a different \
         value. stderr={stderr:?}"
    );
}

/// 2026-05-08 v2 runtime profile-data, Phase 1 Task 2 — compile
/// `examples/hello.sigil` with `--emit-symbol-table` and assert the
/// sidecar:
/// - exists at `<output>.symtab`
/// - is non-empty
/// - is sorted by ascending text offset (the writer's contract)
/// - contains the user `main` symbol (demangled)
/// - contains a runtime symbol (passed through verbatim)
/// - every line matches `<16-hex>\t<16-hex>\t<name>`
///
/// Pins the wire format the runtime profile module reads.
#[test]
fn emit_symbol_table_writes_sorted_sidecar_with_main_and_runtime_symbols() {
    let root = workspace_root();
    let sigil_bin = sigil_binary();
    let source = root.join("examples/hello.sigil");

    let bin_path =
        std::env::temp_dir().join(format!("sigil_e2e_emit_symtab_{}", std::process::id()));
    let symtab_path = std::path::PathBuf::from(format!("{}.symtab", bin_path.display()));

    let compile = Command::new(&sigil_bin)
        .arg(&source)
        .arg("-o")
        .arg(&bin_path)
        .arg("--emit-symbol-table")
        .current_dir(&root)
        .output()
        .expect("invoke sigil compiler");
    assert!(
        compile.status.success(),
        "compile failed: stdout={} stderr={}",
        String::from_utf8_lossy(&compile.stdout),
        String::from_utf8_lossy(&compile.stderr),
    );

    let symtab = std::fs::read_to_string(&symtab_path).expect("sidecar should exist");
    let _ = std::fs::remove_file(&bin_path);
    let _ = std::fs::remove_file(&symtab_path);

    assert!(!symtab.is_empty(), "symtab must not be empty");

    let mut prev_offset: Option<u64> = None;
    let mut saw_main = false;
    let mut saw_runtime = false;
    for line in symtab.lines() {
        let fields: Vec<&str> = line.split('\t').collect();
        assert_eq!(
            fields.len(),
            3,
            "line `{line}` must have 3 tab-separated fields"
        );
        assert_eq!(fields[0].len(), 16, "offset column must be 16 hex chars");
        assert_eq!(fields[1].len(), 16, "size column must be 16 hex chars");
        let off = u64::from_str_radix(fields[0], 16).expect("offset hex");
        let size = u64::from_str_radix(fields[1], 16).expect("size hex");
        assert!(size > 0, "all rows have non-zero size by writer contract");
        if let Some(prev) = prev_offset {
            assert!(
                off >= prev,
                "rows must be sorted by ascending offset; got {off:x} after {prev:x}"
            );
        }
        prev_offset = Some(off);
        match fields[2] {
            "main" => saw_main = true,
            // Any of these is a runtime FFI symbol with the canonical
            // `sigil_*` non-`sigil_user_` prefix that the demangler
            // passes through verbatim.
            "sigil_alloc"
            | "sigil_gc_init"
            | "sigil_string_new"
            | "sigil_io_println_arm"
            | "sigil_perform" => {
                saw_runtime = true;
            }
            _ => {}
        }
    }
    assert!(saw_main, "demangled `main` must appear in sidecar");
    assert!(
        saw_runtime,
        "at least one runtime FFI symbol must appear in sidecar (sigil_alloc / sigil_gc_init / etc.)"
    );
}

/// 2026-05-08 v2 runtime profile-data, Phase 6 Task 10 — end-to-end
/// smoke. Compile a tiny example with `--emit-symbol-table`, run it
/// under `SIGIL_CPU_PROFILE=<tmp>/cpu.pb` with a short
/// `SIGIL_CPU_PROFILE_HZ`, and assert:
/// - the program exits 0;
/// - the output file exists and is non-empty;
/// - the file looks like pprof (varint-decodable; first byte's
///   field-number is 1 = `sample_type`).
///
/// This is the integration test for the full Phase 3 → Phase 5
/// path on the linux-x86_64 host. macOS aarch64 is exercised
/// separately by the CI matrix.
#[test]
fn cpu_profile_writes_pprof_when_env_set() {
    let root = workspace_root();
    let sigil_bin = sigil_binary();

    let test_id = std::process::id();
    let bin_path = std::env::temp_dir().join(format!("sigil_e2e_cpu_prof_{test_id}"));
    let symtab_path = std::path::PathBuf::from(format!("{}.symtab", bin_path.display()));
    let profile_path = std::env::temp_dir().join(format!("sigil_e2e_cpu_prof_{test_id}.pb"));

    let _ = std::fs::remove_file(&profile_path);

    // We use a small example that loops enough to take >50ms so
    // the 99 Hz timer fires at least a handful of times. fib_perf
    // computes fib(20) in <50ms which is borderline; nudge it by
    // looping the perf script. Use fib_cps_perf which is ~250-500ms
    // and gives the sampler real opportunities.
    let source = root.join("examples/fib_cps_perf.sigil");

    let compile = Command::new(&sigil_bin)
        .arg(&source)
        .arg("-o")
        .arg(&bin_path)
        .arg("--emit-symbol-table")
        .current_dir(&root)
        .output()
        .expect("invoke sigil compiler");
    assert!(
        compile.status.success(),
        "compile failed: stdout={} stderr={}",
        String::from_utf8_lossy(&compile.stdout),
        String::from_utf8_lossy(&compile.stderr),
    );

    let run = Command::new(&bin_path)
        .env("SIGIL_CPU_PROFILE", profile_path.to_str().unwrap())
        .env("SIGIL_CPU_PROFILE_HZ", "999") // 999 Hz boosts hit count
        .output()
        .expect("execute compiled binary");
    let _ = std::fs::remove_file(&bin_path);
    let _ = std::fs::remove_file(&symtab_path);

    assert!(
        run.status.success(),
        "run failed: stdout={} stderr={}",
        String::from_utf8_lossy(&run.stdout),
        String::from_utf8_lossy(&run.stderr),
    );

    let bytes = match std::fs::read(&profile_path) {
        Ok(b) => b,
        Err(e) => panic!("profile file `{}` not created: {e}", profile_path.display()),
    };
    let _ = std::fs::remove_file(&profile_path);

    assert!(
        !bytes.is_empty(),
        "profile output must be non-empty (sampler may have missed all ticks)"
    );

    // Tiny pprof sanity: read the first protobuf tag. We expect
    // field 1 (sample_type) with wire-type 2 (length-delimited).
    // tag = (1 << 3) | 2 = 0x0A. The varint decoder for a 1-byte
    // tag is just the byte itself when < 0x80.
    let first = bytes[0];
    assert_eq!(
        first, 0x0A,
        "first protobuf tag in pprof output must be `field 1, wire 2` = 0x0A; got 0x{first:02x}"
    );
}

