// ===== Plan E2 Phase 3 Task 12 — deep recursion + GC stress ===============
//
// Task 12 drops Boehm's conservative stack scan on Sigil program threads
// (via `GC_do_blocking` wrapping `sigil_run_loop`) and substitutes the
// precise stackmap-driven walker installed at
// `GC_set_push_other_roots`. The walker is invoked from inside Boehm's
// mark phase with a captured FP that points into sigil_alloc's frame,
// then iterates UP the FP chain yielding precise roots for every
// stackmap entry along the way.
//
// The compiled binary runs with the production wiring active
// (`#[cfg(not(test))]`); these e2e tests are how we exercise the
// integrated path. The pre-existing `cross_check_tree_stress_*` tests
// (above) cover GC pressure ×depth-12-15 with the cross-check
// asserting precise/conservative parity per safepoint. The tests
// below add the *deep recursion axis* — pinning that the walker
// correctly traverses a long Sigil call chain (~200+ frames) and
// preserves every per-frame heap root across whatever GC events
// Boehm decides to schedule.
//
// Why focus on depth rather than alloc volume:
//   - Volume coverage exists (tree_stress_repeat_large ≈ 983k allocs).
//   - The walker's per-frame correctness scales linearly with depth;
//     a depth-200 traversal exercises 200 distinct stackmap lookups,
//     200 distinct FP-chain hops, and 200 frames of live-root
//     preservation across any GC that fires during the run.
//   - A walker bug that silently drops every Nth frame's roots would
//     surface as a wrong sum or crash in these tests, even if the
//     existing depth-15 tree workload happened to mask it.

#[test]
fn precise_walker_deep_build_sum_chain() {
    // Builds a 1000-deep linked list via non-tail-call recursion
    // (1000 frames of `build_nontco` live on the C stack during the
    // descent — wrapping the recursive call in the `C(n, ...)`
    // constructor defeats TCO so the chain stays unfolded), then
    // folds it back through a 1000-deep `sum_list` recursion (also
    // non-tail by construction: the result `v + sum_list(rest)`
    // combines after the call returns). Every safepoint in either
    // recursion must have its heap root walked correctly by the
    // Task 12 precise walker — a missed root in any single frame
    // loses the partial list and produces a wrong sum or a crash
    // via free-while-reachable.
    //
    // Sum of 1..1000 = 1000 * 1001 / 2 = 500_500.
    let source = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               type Cons = | Nil | C(Int, Cons)\n\
               fn build_nontco(n: Int) -> Cons ![] {\n\
               match n {\n\
               0 => Nil,\n\
               _ => C(n, build_nontco(n - 1)),\n\
               }\n\
               }\n\
               fn sum_list(c: Cons) -> Int ![] {\n\
               match c {\n\
               Nil => 0,\n\
               C(v, rest) => v + sum_list(rest),\n\
               }\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let xs: Cons = build_nontco(1000);\n\
               perform IO.println(int_to_string(sum_list(xs)));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = compile_and_run(source, "precise_walker_deep_build_sum_chain");
    assert!(stderr.is_empty(), "unexpected stderr: {stderr:?}");
    assert_eq!(code, 0, "deep build-sum chain must exit 0");
    assert_eq!(stdout.trim_end(), "500500");
}

#[test]
fn precise_walker_deep_chain_with_gc_pressure() {
    // Deep recursion + alloc volume in one workload: build a
    // 1000-deep list via non-TCO recursion, sum it, repeat 5 rounds.
    // Per round = 1000 cons cells across 1000 stack frames; total
    // 5,000 cons allocations. The outer `iter` is tail-recursive so
    // it stays O(1) on the C stack — the depth axis comes from
    // `build_nontco`/`sum_list`.
    //
    // With the Task 12 wrapping in place the precise walker must:
    //   - Find each build_nontco frame's in-flight live values at
    //     every safepoint of the 1000-deep `build_nontco` chain.
    //   - Find `rest` at every frame of the 1000-deep `sum_list`
    //     chain.
    //   - Find `xs` at the calling `iter` frame across all 5 rounds.
    //   - Walk all of the above from the captured FP without dipping
    //     into libgc's internal frames (PR #170's SIGSEGV root cause).
    //
    // Per round sum = 1000 * 1001 / 2 = 500_500. 5 rounds = 2_502_500.
    let source = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               type Cons = | Nil | C(Int, Cons)\n\
               fn build_nontco(n: Int) -> Cons ![] {\n\
               match n {\n\
               0 => Nil,\n\
               _ => C(n, build_nontco(n - 1)),\n\
               }\n\
               }\n\
               fn sum_list(c: Cons) -> Int ![] {\n\
               match c {\n\
               Nil => 0,\n\
               C(v, rest) => v + sum_list(rest),\n\
               }\n\
               }\n\
               fn iter(rounds: Int, depth: Int, total: Int) -> Int ![] {\n\
               match rounds {\n\
               0 => total,\n\
               _ => {\n\
               let xs: Cons = build_nontco(depth);\n\
               iter(rounds - 1, depth, total + sum_list(xs))\n\
               },\n\
               }\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let total: Int = iter(5, 1000, 0);\n\
               perform IO.println(int_to_string(total));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) =
        compile_and_run(source, "precise_walker_deep_chain_with_gc_pressure");
    assert!(stderr.is_empty(), "unexpected stderr: {stderr:?}");
    assert_eq!(code, 0, "deep chain with GC pressure must exit 0");
    assert_eq!(stdout.trim_end(), "2502500");
}

#[test]
fn precise_walker_deep_chain_under_cross_check() {
    // Same shape as `precise_walker_deep_build_sum_chain` (1000-deep
    // non-TCO recursion), but with `SIGIL_GC_CROSS_CHECK=1`. The
    // cross-check fires at every `sigil_alloc` and asserts that
    // every precise root the stackmap walker yields is (a) inside
    // the calling thread's stack range and (b) heap-pointer-shaped
    // per Boehm's view. A walker bug that surfaces a stale FP or a
    // wrong frame_sp would diverge here on every safepoint along
    // the 1000-deep chain — and because the cross-check fires at
    // EVERY sigil_alloc (~1000 firings during the build), even a
    // one-in-a-thousand walker bug surfaces deterministically.
    let source = "import std.int\n\
               import std.io\n\
               use std.int.{int_to_string};\n\
               use std.io.{IO};\n\
               type Cons = | Nil | C(Int, Cons)\n\
               fn build_nontco(n: Int) -> Cons ![] {\n\
               match n {\n\
               0 => Nil,\n\
               _ => C(n, build_nontco(n - 1)),\n\
               }\n\
               }\n\
               fn sum_list(c: Cons) -> Int ![] {\n\
               match c {\n\
               Nil => 0,\n\
               C(v, rest) => v + sum_list(rest),\n\
               }\n\
               }\n\
               fn main() -> Int ![IO] {\n\
               let xs: Cons = build_nontco(1000);\n\
               perform IO.println(int_to_string(sum_list(xs)));\n\
               0\n\
               }\n";
    let (stdout, stderr, code) = {
        let src_path = std::env::temp_dir().join(format!(
            "sigil_e2e_{}_{}.sigil",
            "precise_walker_deep_chain_under_cross_check",
            std::process::id()
        ));
        std::fs::write(&src_path, source).expect("write source");
        let out = compile_file_and_run_with_env(
            &src_path,
            "precise_walker_deep_chain_under_cross_check",
            &[("SIGIL_GC_CROSS_CHECK", "1")],
        );
        let _ = std::fs::remove_file(&src_path);
        out
    };
    assert_no_cross_check_abort("deep_chain.sigil", &stderr, code);
    assert_eq!(stdout.trim_end(), "500500");
    assert_eq!(code, 0);
}

#[test]
fn cross_check_json_parse_large_array_no_abort() {
    // GC cross-check for deep-recursion path via large JSON parsing.
    // Parses a 10,000 element JSON array (deep recursion in the
    // JSON parser) under SIGIL_GC_CROSS_CHECK=1 to assert the
    // precise walker's roots agree with conservative scan across
    // continuation-stack growth. The cross-check fires at every
    // alloc (~10,000 times during parsing) and verifies no roots
    // diverge and no continuation pointers are missed.
    let elements: Vec<String> = (0..10000).map(|i| i.to_string()).collect();
    let json_string = format!("[{}]", elements.join(", "));
    let escaped_json = json_string.replace('\\', "\\\\").replace('"', "\\\"");

    let src = format!(
        "import std.byte_array\n\
        import std.io\n\
        import std.mem\n\
        import std.string\n\
        import std.json\n\
        import std.result\n\
        use std.byte_array.{{string_to_bytes}};\n\
        use std.io.{{IO}};\n\
        use std.json.{{json_parse}};\n\
        use std.mem.{{Mem}};\n\
        use std.result.{{Err, Ok}};\n\
        use std.string.{{string_concat}};\n\
        fn main() -> Int ![IO, Mem] {{\n\
        match json_parse(string_to_bytes(\"{}\")) {{\n\
        Ok(_) => perform IO.println(\"OK\"),\n\
        Err(msg) => perform IO.println(string_concat(\"ERR: \", msg)),\n\
        }};\n\
        0\n\
        }}\n",
        escaped_json
    );

    let (stdout, stderr, code) = {
        let src_path = std::env::temp_dir().join(format!(
            "sigil_e2e_{}_{}.sigil",
            "cross_check_json_parse_large_array",
            std::process::id()
        ));
        std::fs::write(&src_path, &src).expect("write source");
        let out = compile_file_and_run_with_env(
            &src_path,
            "cross_check_json_parse_large_array",
            &[("SIGIL_GC_CROSS_CHECK", "1")],
        );
        let _ = std::fs::remove_file(&src_path);
        out
    };
    assert_no_cross_check_abort("json_parse_large_array.sigil", &stderr, code);
    assert_eq!(stdout.trim_end(), "OK");
    assert_eq!(code, 0);
}

// ===== Plan A1 — Auto-CPS-promote non-tail self-recursive Sync fns =========
//
// The plan eliminates the silent OS-stack-overflow class for Sigil
// functions with non-tail self-calls. Pre-Plan-A1, a `sum_to(n) = n +
// sum_to(n-1)` at depth 1_000_000 segfaulted (exit 139). Post-plan,
// any fn with a non-tail self-call is auto-promoted to CPS color so
// the trampoline handles unbounded recursion depth at ~5-10× per-call
// cost.
//
// The tests below pin:
//   - depth-1M non-tail self-recursion runs cleanly (was segfault),
//   - tail-recursive self-call stays Sync (perf-floor regression check),
//   - non-recursive fns stay Native (`--dump-color` assertion),
//   - the W0001 info diagnostic surfaces on `--human-errors`,
//   - auto-promotion composes with handler installation,
//   - mutual recursion still segfaults at depth (v1 scope boundary —
//     `#[ignore]`'d with a named successor: a future SCC-based detector
//     promotes the WHOLE cycle to CPS, not just direct self-recursion).

#[test]
fn non_tail_self_recursive_handles_1m_depth() {
    // Pre-Plan-A1: this segfaulted at depth ~100k–1M on the host OS
    // stack. Post-plan: auto-promoted to CPS, runs cleanly via the
    // trampoline. Sum 1..1_000_000 = 500_000_500_000.
    let source = "import std.int\n\
import std.io\n\
use std.int.{int_to_string};\n\
use std.io.{IO};\n\
fn sum_to(n: Int) -> Int ![] {\n\
  if n <= 0 { 0 } else { n + sum_to(n - 1) }\n\
}\n\
fn main() -> Int ![IO] {\n\
  perform IO.println(int_to_string(sum_to(1000000)));\n\
  0\n\
}\n";
    let (stdout, stderr, code) = compile_and_run(source, "non_tail_self_recursive_1m");
    assert_eq!(code, 0, "expected clean exit; stderr={stderr}");
    assert_eq!(stdout.trim_end(), "500000500000");
}

#[test]
fn tail_self_recursive_stays_native_under_dump_color() {
    // `loop_n(n, acc)` calls itself in tail position. The auto-
    // promotion logic must NOT fire here — the existing Sync->Sync
    // TCO (return_call) handles unbounded depth at zero per-call
    // overhead. `--dump-color` is the structural assertion: `loop_n`
    // line starts with `loop_n native`. A regression that
    // over-promotes tail-recursive fns would show `loop_n cps`.
    let source = "fn loop_n(n: Int, acc: Int) -> Int ![] {\n\
  if n <= 0 { acc } else { loop_n(n - 1, acc + 1) }\n\
}\n\
fn main() -> Int ![] {\n\
  loop_n(1000, 0)\n\
}\n";
    let src_path = std::env::temp_dir().join(format!(
        "sigil_e2e_tail_self_recursive_stays_native_{}.sigil",
        std::process::id()
    ));
    std::fs::write(&src_path, source).expect("write source");
    let sigil_bin = sigil_binary();
    let out = Command::new(&sigil_bin)
        .arg(&src_path)
        .arg("--dump-color")
        .output()
        .expect("invoke sigil --dump-color");
    let _ = std::fs::remove_file(&src_path);
    let stdout = String::from_utf8_lossy(&out.stdout);
    let stderr = String::from_utf8_lossy(&out.stderr);
    assert!(
        out.status.success(),
        "--dump-color failed: stdout={stdout}, stderr={stderr}"
    );
    // Exact line shape: `<name> <color> <reason>`. Check loop_n stays
    // native AND that no auto-promotion W0001 info appears on stderr.
    assert!(
        stdout.lines().any(|l| l.starts_with("loop_n native ")),
        "loop_n must be native in --dump-color output:\n{stdout}"
    );
    // W0001 would appear on stderr only with --human-errors. Pin that
    // no informational diagnostic fires regardless: a stray emission
    // would mean the auto-promotion misfired.
    assert!(
        !stderr.contains("W0001"),
        "no W0001 should fire for tail-recursive loop_n: stderr={stderr}"
    );
}

